import { useState, useEffect } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { coursesService } from '../../services/courses';
import { enrollmentsService } from '../../services/enrollments';
import { authService } from '../../services/auth';
import './CourseDetail.css';

const CourseDetail = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [course, setCourse] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [enrolling, setEnrolling] = useState(false);
  const [isEnrolled, setIsEnrolled] = useState(false);

  useEffect(() => {
    loadCourse();
    checkEnrollment();
  }, [id]);

  const loadCourse = async () => {
    try {
      setLoading(true);
      const data = await coursesService.getById(id);
      setCourse(data);
    } catch (err) {
      setError('Failed to load course');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const checkEnrollment = async () => {
    if (!authService.isAuthenticated()) return;
    try {
      const enrolled = await enrollmentsService.checkEnrollment(id);
      setIsEnrolled(enrolled);
    } catch (err) {
      console.error(err);
    }
  };

  const handleEnroll = async () => {
    if (!authService.isAuthenticated()) {
      navigate('/login');
      return;
    }

    try {
      setEnrolling(true);
      await enrollmentsService.enroll(id);
      setIsEnrolled(true);
      // Reload course to get full content
      await loadCourse();
      alert('Successfully enrolled! You can now access the course content.');
    } catch (err) {
      const errorMsg =
        err.response?.data?.course_id?.[0] ||
        err.response?.data?.non_field_errors?.[0] ||
        'Failed to enroll. Please try again.';
      alert(errorMsg);
    } finally {
      setEnrolling(false);
    }
  };

  const handleViewContent = () => {
    const contentSection = document.getElementById('course-content');
    if (contentSection) {
      contentSection.scrollIntoView({ behavior: 'smooth' });
    }
  };

  if (loading) {
    return <div className="loading">Loading course...</div>;
  }

  if (error || !course) {
    return <div className="error-message">{error || 'Course not found'}</div>;
  }

  return (
    <div className="course-detail">
      <div className="course-header">
        <div className="course-image-large">
          {course.image_url ? (
            <img src={course.image_url} alt={course.title} />
          ) : (
            <div className="course-image-placeholder-large">No Image</div>
          )}
        </div>
        <div className="course-header-info">
          <h1>{course.title}</h1>
          <p className="course-instructor">
            Instructor: {course.instructor_name || course.instructor_email}
          </p>
          <p className="course-description">{course.description}</p>
          <div className="course-stats">
            <span>{course.total_sections} Sections</span>
            <span>{course.total_lectures} Lectures</span>
          </div>
          <div className="course-actions">
            <span className="course-price-large">
              ${parseFloat(course.price).toFixed(2)}
            </span>
            {isEnrolled ? (
              <button
                onClick={handleViewContent}
                className="btn btn-success"
              >
                Continue Learning
              </button>
            ) : (
              <button
                onClick={handleEnroll}
                disabled={enrolling}
                className="btn btn-primary"
              >
                {enrolling ? 'Enrolling...' : 'Enroll Now'}
              </button>
            )}
          </div>
        </div>
      </div>

      {course.sections && course.sections.length > 0 && (
        <div id="course-content" className="course-content">
          <h2>Course Content</h2>
          {!isEnrolled && (
            <div className="enrollment-notice">
              <p>Enroll to access course content</p>
            </div>
          )}
          {isEnrolled &&
            course.sections.map((section) => (
              <div key={section.id} className="section">
                <h3>{section.title}</h3>
                {section.description && <p>{section.description}</p>}
                {section.lectures && section.lectures.length > 0 && (
                  <ul className="lectures-list">
                    {section.lectures.map((lecture) => (
                      <li key={lecture.id} className="lecture-item">
                        <span>{lecture.title}</span>
                        {lecture.duration_minutes > 0 && (
                          <span className="lecture-duration">
                            {lecture.duration_minutes} min
                          </span>
                        )}
                      </li>
                    ))}
                  </ul>
                )}
              </div>
            ))}
        </div>
      )}
    </div>
  );
};

export default CourseDetail;
